import React, { useState, useEffect } from 'react';
import {
  NavLink as RouterLink,
  matchPath,
  useLocation,
  useHistory,
} from 'react-router-dom';
import PropTypes from 'prop-types';
import { Collapse, List, ListItemButton, Box, Typography, alpha, useTheme } from '@mui/material';
import { ChevronRight, ChevronDown } from 'react-feather';
import _ from 'lodash';
import accessRight from '../../utils/functions/accessRight';

const NavItem = ({ href, icon: Icon, title, sub, moduleName, me }) => {
  const history = useHistory();
  const location = useLocation();
  const theme = useTheme();
  
  const active = href
    ? !!matchPath(location.pathname, {
        path: href,
        exact: !_.size(sub), // Exact match if no sub-items
      })
    : false;
    
  const [open, setOpen] = useState(active);

  // Auto-open if a child is active
  useEffect(() => {
     if (_.size(sub)) {
        const isChildActive = sub.some(item => matchPath(location.pathname, { path: item.href }));
        if (isChildActive) setOpen(true);
     }
  }, [location.pathname, sub]);

  const handleClick = () => {
    if (_.size(sub)) {
        setOpen(!open);
    } else {
        history.push(href);
    }
  };

  const commonSx = {
    borderRadius: 2,
    mb: 0.5,
    py: 1.2,
    px: 2,
    transition: 'all 0.2s ease-in-out',
    '&:hover': {
        backgroundColor: alpha(theme.palette.primary.main, 0.08),
        color: theme.palette.primary.main,
    }
  };

  return (
    <Box sx={{ px: 1.5, py: 0.5 }}>
      <ListItemButton
        onClick={handleClick}
        sx={{
          ...commonSx,
          ...(active && !_.size(sub) && {
            backgroundColor: alpha(theme.palette.primary.main, 0.12),
            color: 'primary.main',
            fontWeight: 600,
            '& .feather': {
                color: 'primary.main',
            }
          }),
          ...(!active && {
            color: 'text.secondary',
          }),
        }}
      >
        <Box sx={{ display: 'flex', alignItems: 'center', flexGrow: 1 }}>
            {Icon && (
                <Box component="span" sx={{ mr: 1.5, display: 'flex', alignItems: 'center' }}>
                    <Icon size="20" />
                </Box>
            )}
            <Typography variant="body2" sx={{ fontWeight: active ? 600 : 500 }}>
                {title}
            </Typography>
        </Box>
        
        {_.size(sub) > 0 && (
            <Box component="span" sx={{ ml: 1, display: 'flex' }}>
              {open ? <ChevronDown size="16" /> : <ChevronRight size="16" />}
            </Box>
        )}
      </ListItemButton>

      {_.size(sub) > 0 && (
        <Collapse in={open} timeout="auto" unmountOnExit>
          <List component="div" disablePadding sx={{ mt: 0.5 }}>
            {_.map(sub, (item, index) => {
              if (accessRight(me, moduleName, item.level)) {
                const isSubActive = matchPath(location.pathname, { path: item.href });
                return (
                    <ListItemButton
                      key={index}
                      component={RouterLink}
                      to={item.href}
                      sx={{
                        borderRadius: 2,
                        pl: 5,
                        py: 1,
                        mb: 0.5,
                        color: isSubActive ? 'primary.main' : 'text.secondary',
                        backgroundColor: isSubActive ? alpha(theme.palette.primary.main, 0.08) : 'transparent',
                        '&:hover': {
                           color: 'primary.main',
                           backgroundColor: alpha(theme.palette.primary.main, 0.04),
                        }
                      }}
                    >
                        <Box sx={{ 
                            width: 6, 
                            height: 6, 
                            borderRadius: '50%', 
                            bgcolor: isSubActive ? 'primary.main' : alpha(theme.palette.text.secondary, 0.4),
                            mr: 2
                        }} />
                      <Typography variant="body2" sx={{ fontWeight: isSubActive ? 600 : 400 }}>
                        {item.title}
                      </Typography>
                    </ListItemButton>
                );
              }
              return null;
            })}
          </List>
        </Collapse>
      )}
    </Box>
  );
};

NavItem.propTypes = {
  href: PropTypes.string,
  icon: PropTypes.elementType,
  title: PropTypes.string,
  sub: PropTypes.array,
  me: PropTypes.object,
  moduleName: PropTypes.string,
};

export default NavItem;
